// === INPUT: только из ноды "Цикл" ===
const keysRaw = $item(0).$node["Цикл"].json["Ключи"];

// --- Time guard ---
const BUDGET_MS = 10000;                   // ваш лимит
const deadline = Date.now() + BUDGET_MS;
const checkTime = () => {
  if (Date.now() > deadline) {
    throw new Error(`Code node timed out after ${BUDGET_MS} ms`);
    // Либо вместо throw — вернуть частичный результат, см. ниже.
  }
};

// --- Helpers ---
const toStringSafe = v => (v == null ? "" : String(v));
const normalize = s =>
  toStringSafe(s).toLowerCase().normalize("NFKD").replace(/[\u0300-\u036f]/g, "");

const tokenize = s => {
  checkTime();
  const m = toStringSafe(s).toLowerCase().match(/\p{L}[\p{L}\p{Nd}-]*/gu);
  return m || [];
};

const ngrams = (tokens, n) => {
  checkTime();
  const res = [];
  for (let i = 0; i <= tokens.length - n; i++) {
    // периодически проверяем время в длинных циклах
    if ((i & 15) === 0) checkTime();
    res.push(tokens.slice(i, i + n).join(" "));
  }
  return res;
};

// --- Prepare keys ---
let keysArr;
if (Array.isArray(keysRaw)) {
  keysArr = keysRaw
    .flatMap(k => (typeof k === "string" ? k.split(/\s*[,;|\n]\s*/g) : []))
    .map(s => s.trim())
    .filter(Boolean);
} else {
  keysArr = toStringSafe(keysRaw).split(/\s*[,;|\n]\s*/g).map(s => s.trim()).filter(Boolean);
}
checkTime();

// --- Per-key stats & n-grams (2..3) ---
const grams2 = new Set();
const grams3 = new Set();

const perKeyword = [];
for (let idx = 0; idx < keysArr.length; idx++) {
  if ((idx & 7) === 0) checkTime();   // проверяем каждые ~8 элементов
  const k = keysArr[idx];
  const toks = tokenize(k);
  ngrams(toks, 2).forEach(g => grams2.add(g));
  ngrams(toks, 3).forEach(g => grams3.add(g));
  perKeyword.push({ keyword: k, wordCount: toks.length });
}

// --- Output ---
return [
  {
    json: {
      keywords: keysArr,
      perKeyword,
      totalKeywords: keysArr.length,
      ngrams2: Array.from(grams2),
      ngrams3: Array.from(grams3),
      // Дополнительно можете вернуть фактическое время:
      elapsedMs: BUDGET_MS - Math.max(0, deadline - Date.now()),
    },
  },
];

// === INPUT: только из ноды "Редактура и проверка вписывания ссылок" ===
const inputTextRaw = $item(0).$node["Редактура и проверка вписывания ссылок"].json["output"];

// --- Helpers ---
const toStringSafe = v => (v == null ? "" : String(v));
const tokenize = s => {
  const m = toStringSafe(s).toLowerCase().match(/\p{L}[\p{L}\p{Nd}-]*/gu);
  return m || [];
};

const splitSentences = s => {
  // простая эвристика для предложений
  const arr = toStringSafe(s)
    .replace(/\s+/g, " ")
    .trim()
    .split(/(?<=[\.\!\?])\s+(?=[^\s])/g)
    .filter(Boolean);
  return arr;
};

// --- Compute text metrics ---
const inputText = toStringSafe(inputTextRaw);
const tokens = tokenize(inputText);
const totalWords = tokens.length;
const uniqueWords = new Set(tokens).size;
const sentences = splitSentences(inputText);
const sentenceCount = sentences.length;

const avgWordLen = totalWords
  ? +(tokens.reduce((s, w) => s + w.length, 0) / totalWords).toFixed(3)
  : 0;

const avgWordsPerSentence = sentenceCount
  ? +(totalWords / sentenceCount).toFixed(3)
  : 0;

// --- Output ---
return [
  {
    json: {
      inputText,
      totalWords,             // объём слов во входном тексте
      uniqueWords,
      sentenceCount,
      avgWordLen,
      avgWordsPerSentence,
    },
  },
];

